        type="button"
        aria-expanded={open}
        aria-controls={menuId}
        aria-haspopup="menu"
        data-testid="lens-dropdown-trigger"
        onClick={() => setOpen((v) => !v)}
        style={
          softColor
            ? {
                borderLeft: `3px solid ${softColor}`,
                paddingLeft: '0.375rem',
              }
            : undefined
        }
        className="rounded-sm px-1.5 py-0.5 hover:bg-surface-strong"
        onKeyDown={(e) => {
          if (e.key === 'Escape') close();
        }}
      >
        Show:{' '}
        <span className="font-medium" style={{ color: 'var(--color-foreground)' }}>
          {LENS_LABELS[activeLensInCycle]}
        </span>
        {' ▾'}
      </button>
      {open ? (
        <div
          id={menuId}
          role="menu"
          aria-label="Lens"
          data-testid="lens-menu"
          className="absolute bottom-full left-0 z-50 mb-1 w-44 rounded-md border border-border bg-surface shadow-elev-2"
          style={{ fontSize: 'var(--text-sm)' }}
        >
          {LENS_CYCLE.map((lens) => (
            <button
              key={lens}
              type="button"
              role="menuitem"
              data-testid={`lens-option-${lens}`}
              onClick={() => {
                onLensChange(lens);
                close();
              }}
              className={[
                'flex w-full items-center justify-between px-3 py-1.5 text-left',
                lens === currentLens ? 'bg-accent-soft font-medium' : 'hover:bg-surface-strong',
              ].join(' ')}
            >
              {LENS_LABELS[lens]}
              {lens === currentLens ? (
                <svg
                  aria-hidden="true"
                  width="12"
                  height="12"
                  viewBox="0 0 12 12"
                  fill="none"
                  stroke="currentColor"
                  strokeWidth="1.8"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                >
                  <polyline points="2,6 5,9 10,3" />
                </svg>
              ) : null}
            </button>
          ))}
        </div>
      ) : null}
    </div>
  );
}

