25	function fmtMm(n: number | null | undefined): string {
26	  if (n == null || !Number.isFinite(n)) return '—';
27	  return String(n);
28	}
29	
30	function isPersistedCutawayStyle(v: unknown): v is OrbitViewCutawayStyleToken {
31	  return v === 'none' || v === 'cap' || v === 'floor' || v === 'box';
32	}
33	
34	function hiddenKindsToCsv(vp: Extract<Element, { kind: 'viewpoint' }>): string {
35	  const kinds = vp.hiddenSemanticKinds3d;
36	  if (kinds == null || kinds.length === 0) return '';
37	  return kinds.join(', ');
