40	/**
41	 * HUD for persisted saved 3D viewpoint clip / cutaway metadata. Read-only when `onPersistField`
42	 * is omitted; otherwise edits round-trip through `updateElementProperty`.
43	 */
44	export function OrbitViewpointPersistedHud(props: OrbitViewpointPersistedHudProps) {
45	  const { activeViewpointId, viewpoint, onPersistField } = props;
