1	import type { JSX } from 'react';
2	import { useMemo } from 'react';
3	
4	import type { Element } from '@bim-ai/core';
5	
6	import { BUILT_IN_FAMILIES } from '../families/familyCatalog';
7	import { LevelStack } from '../levels/LevelStack';
8	import { useBimStore } from '../state/store';
9	import { LeftRail } from './LeftRail';
10	import type { WorkspaceMode } from './TopBar';
11	import { buildBrowserSections } from './workspaceUtils';
12	
13	export function WorkspaceLeftRail({
14	  onSemanticCommand,
15	  openTabFromElement,
16	  onModeChange,
17	  onOpenFamilyLibrary,
18	}: {
19	  onSemanticCommand: (cmd: Record<string, unknown>) => void | Promise<void>;
20	  openTabFromElement: (el: Element) => void;
21	  onModeChange: (mode: WorkspaceMode) => void;
22	  onOpenFamilyLibrary?: () => void;
23	}): JSX.Element {
24	  const elementsById = useBimStore((s) => s.elementsById);
25	  const activeLevelId = useBimStore((s) => s.activeLevelId);
26	  const setActiveLevelId = useBimStore((s) => s.setActiveLevelId);
27	  const selectedId = useBimStore((s) => s.selectedId);
28	  const select = useBimStore((s) => s.select);
29	  const setOrbitCameraFromViewpointMm = useBimStore((s) => s.setOrbitCameraFromViewpointMm);
30	  const setActiveViewpointId = useBimStore((s) => s.setActiveViewpointId);
31	
32	  const browserSections = useMemo(() => buildBrowserSections(elementsById), [elementsById]);
33	
34	  const activeFamilyTypeId = useMemo(() => {
35	    if (!selectedId) return undefined;
36	    const el = elementsById[selectedId];
37	    if (!el) return undefined;
38	    if (el.kind === 'door' || el.kind === 'window') return el.familyTypeId ?? undefined;
39	    return undefined;
