103	export function defaultTabFallbackForKind(
104	  kind: WorkspaceMode | TabKind,
105	  elementsById: Record<string, Element>,
106	  activeLevelId: string | undefined,
107	): { targetId?: string; label: string } | null {
108	  const all = Object.values(elementsById) as Element[];
109	  if (kind === 'plan' || kind === 'plan-3d') {
110	    const levels = all
