import React, { useCallback, useEffect, useState } from 'react';

interface PresentationRecord {
  id: string;
  modelId: string;
  token: string;
  createdBy: string;
  createdAt: number;
  expiresAt?: number;
  isRevoked: boolean;
  openCount: number;
}

interface PageOption {
  id: string;
  name: string;
}

interface Props {
  modelId: string;
  open: boolean;
  onClose: () => void;
  pages?: PageOption[];
}

export function SharePresentationModal({ modelId, open, onClose, pages = [] }: Props) {
  const [presentations, setPresentations] = useState<PresentationRecord[]>([]);
  const [selectedPageIds, setSelectedPageIds] = useState<string[]>([]);
  const [allPages, setAllPages] = useState(true);
  const [allowMeasurement, setAllowMeasurement] = useState(false);

input.prompt:
Wire the "Show: Architecture/Structure/MEP/All" lens dropdown in the StatusBar to actually affect the 3D viewport rendering in bim-ai.

## The problem

In `packages/web/src/workspace/Workspace.tsx:252`, there's local component state:
```ts
const [lensMode, setLensMode] = useState<LensMode>('all');
```
This is passed to the StatusBar (lines 1106–1107) and updated when the user picks a lens, but it **never reaches the Viewport**. The 3D viewport reads lens filtering from `resolveLensFilter(active3dView ?? null)` (Viewport.tsx:1361–1364) which reads `active3dView?.defaultLens` from the model snapshot — not from the UI dropdown at all.

## Types to know

In `packages/core/src/index.ts`:
- `LensMode = 'all' | 'architecture' | 'structure' | 'mep' | 'energy' | 'coordination'` (used by the UI dropdown)
- `ViewLensMode = 'show_arch' | 'show_struct' | 'show_mep' | 'show_all'` (used by saved view elements' `defaultLens`)

## The fix — move lensMode to the store

1. **`packages/web/src/state/storeTypes.ts`** — add to `BimState`:
   ```ts
   lensMode: LensMode;
   setLensMode: (m: LensMode) => void;
   ```
   Follow the exact same pattern as `planPresentationPreset` / `setPlanPresentationPreset` already there.

2. **`packages/web/src/state/store.ts`** — add initial value `lensMode: 'all'` and setter:
   ```ts
   setLensMode: (lensMode) => set(() => ({ lensMode })),
   ```
   Again, follow the `setPlanPresentationPreset` pattern.

3. **`packages/web/src/viewport/useLensFilter.ts`** — add a second exported function that takes `LensMode` directly (don't remove `resolveLensFilter`, just add alongside it):
   ```ts
   import type { Element, LensMode } from '@bim-ai/core';

   const LENS_MODE_TO_DISCIPLINE: Record<string, string> = {
     architecture: 'arch',
     structure: 'struct',
     mep: 'mep',
   };

   export function lensFilterFromMode(
     mode: LensMode,
   ): (elem: Element) => 'foreground' | 'ghost' {
     if (mode === 'all' || mode === 'energy' || mode === 'coordination') {
       return () => 'foreground';
     }
     const expected = LENS_MODE_TO_DISCIPLINE[mode];
     return (elem: Element): 'foreground' | 'ghost' => {
       const disc =
         ('discipline' in elem ? (elem.discipline as string | null | undefined) : null) ?? 'arch';
       return disc === expected ? 'foreground' : 'ghost';
     };
   }
   ```

4. **`packages/web/src/Viewport.tsx`** — replace the existing lens filter source:
   - Import `lensFilterFromMode` from `./viewport/useLensFilter`
   - Import `LensMode` type from `@bim-ai/core`
   - Read `lensMode` from the store: `const lensMode = useBimStore((s) => s.lensMode);`
   - Replace lines 1360–1364 (the `active3dView` lookup + `resolveLensFilter` call) with:
     ```ts
     const lensFilter = lensFilterFromMode(lensMode);
     ```
   - Keep the `resolveLensFilter` import in case it's used elsewhere; if it's only used in those lines, remove it.

5. **`packages/web/src/workspace/Workspace.tsx`** — remove the local `lensMode` useState:
   - Delete `const [lensMode, setLensMode] = useState<LensMode>('all');` (line ~252)
   - Replace with store reads: 
     ```ts
     const lensMode = useBimStore((s) => s.lensMode);
     const setLensMode = useBimStore((s) => s.setLensMode);
     ```
   - Remove unused `useState` import if it becomes unused (check other uses first).

## Verification

After the fix:
- The `lensMode` state lives in the global store
- The Viewport reads it from the store on every render cycle
- Clicking "Architecture" in the StatusBar dropdown ghosts non-arch elements in 3D
- Clicking "All" restores everything to foreground

## Branch naming

Create and commit on branch `fix/lens-dropdown-wiring`. Do not push. Commit message: "fix(viewport): wire lens dropdown to 3D rendering"

## Important notes

- Do NOT run the dev server or tests — just make the code changes
- Prettier will auto-run after each Edit/Write via a post-tool hook, so don't worry about formatting
- TypeScript strict mode is on — make sure all imports and types are correct
- The repo uses pnpm workspace; all packages are in `packages/`

